// HackerNews Lead Scraper for Markexis
// Uses HN Algolia API (free, no key) — searches last 48h for high-intent posts
// Ingests founders via the unified lead-ingest webhook

const INGEST_URL = 'http://67.207.89.85:5678/webhook/lead-ingest';
const HOURS_BACK = 168; // 7 days — niche keywords need wider window
const MAX_PER_QUERY = 15;
const CAP = 20; // max new leads per run

// Keywords matching Markexis ICP needs: LatAm expansion, AI marketing, GTM/growth
const QUERIES = [
  'latam',
  'saas founder',
  'go-to-market',
  'startup marketing',
  'saas marketing',
  'ai marketing',
  'saas growth',
  'b2b saas',
  'latin america',
  'marketing strategy',
];

const since = Math.floor(Date.now() / 1000) - HOURS_BACK * 3600;
const seen = new Set();
const results = [];

for (const query of QUERIES) {
  if (results.length >= CAP) break;

  let res;
  try {
    res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://hn.algolia.com/api/v1/search_by_date?query=${encodeURIComponent(query)}&tags=(story,ask_hn,show_hn)&numericFilters=created_at_i%3E${since}&hitsPerPage=${MAX_PER_QUERY}`,
    });
  } catch (e) {
    continue;
  }

  for (const hit of (res.hits || [])) {
    if (!hit.author || seen.has(hit.author)) continue;
    seen.add(hit.author);
    if (results.length >= CAP) break;

    // Fetch HN user profile for website/bio
    let profile = {};
    try {
      profile = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://hacker-news.firebaseio.com/v0/user/${hit.author}.json`,
      });
    } catch (e) { /* profile optional */ }

    // Strip HTML tags from about field
    const about = ((profile && profile.about) || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

    // Extract domain from about field
    const urlMatch = about.match(/https?:\/\/([^\s<>"']+)/);
    let domain = null;
    if (urlMatch) {
      domain = urlMatch[1].replace(/^www\./, '').split('/')[0].toLowerCase();
      // Skip common non-company domains
      const skip = ['github.com', 'twitter.com', 'linkedin.com', 'youtube.com', 'medium.com', 'substack.com', 'news.ycombinator.com'];
      if (skip.some(s => domain.endsWith(s))) domain = null;
    }

    const lead = {
      name: hit.author,
      email: null,
      company: domain || hit.author,
      domain: domain,
      title: null,
      location: null,
      source_platform: 'hackernews',
      source_url: `https://news.ycombinator.com/user?id=${hit.author}`,
      raw_bio: about || hit.title || `HN user who posted: ${hit.title || ''}`,
      company_size_signal: 'unknown',
      scraped_at: new Date().toISOString(),
    };

    let ingestResult = 'skipped';
    try {
      const r = await this.helpers.httpRequest({
        method: 'POST',
        url: INGEST_URL,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(lead),
      });
      ingestResult = r.status || 'ok';
    } catch (e) {
      ingestResult = `error: ${e.message.slice(0, 80)}`;
    }

    results.push({ author: hit.author, domain, post: hit.title, ingest: ingestResult });

    // Small delay to avoid hammering HN Firebase
    await new Promise(r => setTimeout(r, 300));
  }
}

return [{ json: { scraped: results.length, results } }];
